import 'dart:convert';

import 'torrent.dart';

class Movie {
  int? id;
  String? url;
  String? imdbCode;
  String? title;
  String? titleEnglish;
  String? titleLong;
  String? slug;
  int? year;
  double? rating;
  int? runtime;
  List<String>? genres;
  String? summary;
  String? descriptionFull;
  String? synopsis;
  String? ytTrailerCode;
  String? language;
  String? mpaRating;
  String? backgroundImage;
  String? backgroundImageOriginal;
  String? smallCoverImage;
  String? mediumCoverImage;
  String? largeCoverImage;
  String? state;
  List<Torrent>? torrents;
  String? dateUploaded;
  int? dateUploadedUnix;

  Movie({
    this.id,
    this.url,
    this.imdbCode,
    this.title,
    this.titleEnglish,
    this.titleLong,
    this.slug,
    this.year,
    this.rating,
    this.runtime,
    this.genres,
    this.summary,
    this.descriptionFull,
    this.synopsis,
    this.ytTrailerCode,
    this.language,
    this.mpaRating,
    this.backgroundImage,
    this.backgroundImageOriginal,
    this.smallCoverImage,
    this.mediumCoverImage,
    this.largeCoverImage,
    this.state,
    this.torrents,
    this.dateUploaded,
    this.dateUploadedUnix,
  });

  @override
  String toString() {
    return 'Movie(id: $id, url: $url, imdbCode: $imdbCode, title: $title, titleEnglish: $titleEnglish, titleLong: $titleLong, slug: $slug, year: $year, rating: $rating, runtime: $runtime, genres: $genres, summary: $summary, descriptionFull: $descriptionFull, synopsis: $synopsis, ytTrailerCode: $ytTrailerCode, language: $language, mpaRating: $mpaRating, backgroundImage: $backgroundImage, backgroundImageOriginal: $backgroundImageOriginal, smallCoverImage: $smallCoverImage, mediumCoverImage: $mediumCoverImage, largeCoverImage: $largeCoverImage, state: $state, torrents: $torrents, dateUploaded: $dateUploaded, dateUploadedUnix: $dateUploadedUnix)';
  }

  factory Movie.(
    Map<String, dynamic> data,
  ) {
    return Movie(
      id: data['id'] as int?,
      url: data['url'] as String?,
      imdbCode: data['imdb_code'] as String?,
      title: data['title'] as String?,
      titleEnglish: data['title_english'] as String?,
      titleLong: data['title_long'] as String?,
      slug: data['slug'] as String?,
      year: data['year'] as int?,
      rating: (data['rating'] as num?)?.toDouble(),
      runtime: data['runtime'] as int?,
      genres: data['genres'] as List<String>?,
      summary: data['summary'] as String?,
      descriptionFull: data['description_full'] as String?,
      synopsis: data['synopsis'] as String?,
      ytTrailerCode: data['yt_trailer_code'] as String?,
      language: data['language'] as String?,
      mpaRating: data['mpa_rating'] as String?,
      backgroundImage: data['background_image'] as String?,
      backgroundImageOriginal: data['background_image_original'] as String?,
      smallCoverImage: data['small_cover_image'] as String?,
      mediumCoverImage: data['medium_cover_image'] as String?,
      largeCoverImage: data['large_cover_image'] as String?,
      state: data['state'] as String?,
      torrents: (data['torrents'] as List<dynamic>?)
          ?.map(
            (e) =>
                Torrent.(
                  e as Map<String, dynamic>,
                ),
          )
          .toList(),
      dateUploaded: data['date_uploaded'] as String?,
      dateUploadedUnix: data['date_uploaded_unix'] as int?,
    );
  }

  Map<String, dynamic>
  () {
    return {
      'id': id,
      'url': url,
      'imdb_code': imdbCode,
      'title': title,
      'title_english': titleEnglish,
      'title_long': titleLong,
      'slug': slug,
      'year': year,
      'rating': rating,
      'runtime': runtime,
      'genres': genres,
      'summary': summary,
      'description_full': descriptionFull,
      'synopsis': synopsis,
      'yt_trailer_code': ytTrailerCode,
      'language': language,
      'mpa_rating': mpaRating,
      'background_image': backgroundImage,
      'background_image_original': backgroundImageOriginal,
      'small_cover_image': smallCoverImage,
      'medium_cover_image': mediumCoverImage,
      'large_cover_image': largeCoverImage,
      'state': state,
      'torrents': torrents
          ?.map(
            (e) => e
                .(),
          )
          .toList(),
      'date_uploaded': dateUploaded,
      'date_uploaded_unix': dateUploadedUnix,
    };
  }

  /// `dart:convert`
  ///
  /// Parses the string and returns the resulting Json object as [Movie].
  factory Movie.fromJson(String data) {
    return Movie.(
      json.decode(data) as Map<String, dynamic>,
    );
  }

  /// `dart:convert`
  ///
  /// Converts [Movie] to a JSON string.
  String toJson() => json.encode(
    (),
  );

  Movie copyWith({
    int? id,
    String? url,
    String? imdbCode,
    String? title,
    String? titleEnglish,
    String? titleLong,
    String? slug,
    int? year,
    double? rating,
    int? runtime,
    List<String>? genres,
    String? summary,
    String? descriptionFull,
    String? synopsis,
    String? ytTrailerCode,
    String? language,
    String? mpaRating,
    String? backgroundImage,
    String? backgroundImageOriginal,
    String? smallCoverImage,
    String? mediumCoverImage,
    String? largeCoverImage,
    String? state,
    List<Torrent>? torrents,
    String? dateUploaded,
    int? dateUploadedUnix,
  }) {
    return Movie(
      id: id ?? this.id,
      url: url ?? this.url,
      imdbCode: imdbCode ?? this.imdbCode,
      title: title ?? this.title,
      titleEnglish: titleEnglish ?? this.titleEnglish,
      titleLong: titleLong ?? this.titleLong,
      slug: slug ?? this.slug,
      year: year ?? this.year,
      rating: rating ?? this.rating,
      runtime: runtime ?? this.runtime,
      genres: genres ?? this.genres,
      summary: summary ?? this.summary,
      descriptionFull: descriptionFull ?? this.descriptionFull,
      synopsis: synopsis ?? this.synopsis,
      ytTrailerCode: ytTrailerCode ?? this.ytTrailerCode,
      language: language ?? this.language,
      mpaRating: mpaRating ?? this.mpaRating,
      backgroundImage: backgroundImage ?? this.backgroundImage,
      backgroundImageOriginal:
          backgroundImageOriginal ?? this.backgroundImageOriginal,
      smallCoverImage: smallCoverImage ?? this.smallCoverImage,
      mediumCoverImage: mediumCoverImage ?? this.mediumCoverImage,
      largeCoverImage: largeCoverImage ?? this.largeCoverImage,
      state: state ?? this.state,
      torrents: torrents ?? this.torrents,
      dateUploaded: dateUploaded ?? this.dateUploaded,
      dateUploadedUnix: dateUploadedUnix ?? this.dateUploadedUnix,
    );
  }
}
